// Validate Slack request signature (X-Slack-Signature)
// HMAC pattern adapted from n8n-approve-ticket.json
const crypto = require('crypto');

const signature = $input.first().json.headers['x-slack-signature'];
const timestamp = $input.first().json.headers['x-slack-request-timestamp'];
const rawBody = $input.first().json.body;

const signingSecret = $env.SLACK_SIGNING_SECRET;

if (!signingSecret) {
  throw new Error('SLACK_SIGNING_SECRET not configured — set it as Docker env var');
}

// Replay attack protection: reject if timestamp > 5 minutes old
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > 300) {
  throw new Error('Request timestamp too old — possible replay attack');
}

// Compute expected signature: v0=HMAC-SHA256(secret, v0:timestamp:body)
const sigBasestring = `v0:${timestamp}:${rawBody}`;
const expected = 'v0=' + crypto.createHmac('sha256', signingSecret)
  .update(sigBasestring)
  .digest('hex');

if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
  throw new Error('Invalid Slack signature');
}

// Parse the interactive payload
const payload = JSON.parse(decodeURIComponent(rawBody.replace('payload=', '')));
const action = payload.actions?.[0] || {};
const actionId = action.action_id || '';
const userId = payload.user?.id || '';

return [{
  json: {
    actionId,
    actionValue: action.value || '',
    userId,
    userName: payload.user?.name || '',
    triggerId: payload.trigger_id || '',
    responseUrl: payload.response_url || '',
    valid: true
  }
}];

// Tiered access control for Slack AI Factory actions
// admin: all actions (scan, implement, approve, merge)
// allowed: approve + merge only
// readonly: 403 forbidden
// Backward compatible: empty SLACK_ADMIN_USERS = all allowed users are admins
const adminUsers = ($env.SLACK_ADMIN_USERS || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

const allowedUsers = ($env.SLACK_ALLOWED_USERS || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

const userId = $input.first().json.userId;
const actionId = $input.first().json.actionId || '';

// Determine tier
let tier = 'readonly';
if (adminUsers.length > 0 && adminUsers.includes(userId)) {
  tier = 'admin';
} else if (adminUsers.length === 0 && allowedUsers.length > 0 && allowedUsers.includes(userId)) {
  tier = 'admin'; // backward compat: no admin list = allowed users are admins
} else if (allowedUsers.includes(userId)) {
  tier = 'allowed';
}

// Check access
if (tier === 'readonly') {
  if (allowedUsers.length > 0) {
    throw new Error(`User ${userId} not authorized (tier: readonly)`);
  }
  // No allowlist configured = open access (backward compat)
  tier = 'admin';
}

// Admin-only actions: scan, implement
const adminOnlyPrefixes = ['scan_backlog:', 'trigger_implement:'];
const isAdminAction = adminOnlyPrefixes.some(p => actionId.startsWith(p));
if (isAdminAction && tier !== 'admin') {
  throw new Error(`Action ${actionId} requires admin tier (user ${userId} has tier: ${tier})`);
}

return [{ json: { ...($input.first().json), tier } }];
